  @state toolbar = chrome.makeToolbar()  @ 23   -- one shared toolbar; renders the active page's row
  @state bridge  @ 28
  @state facades, debugHandles = {}, {}  @ 36
  @state facade = {  @ 37
  @state STD = { cm = cm, ds = ds, eventMeta = eventMeta, cmgr = cmgr, c...  @ 43
  @state CHROME_PAD_X, CHROME_PAD_Y = 8, 4  @ 45
  @state pages, active, previous = {}, nil, nil  @ 47
  @state lastToolbarActive = nil  @ 48   -- last page measured; a switch re-pins the band height
  @state bootSettled = false  @ 49   -- latched once boot transients (fonts, window width) settle
  @state bootFrames = 0  @ 50
  @state lastAvailW = nil  @ 51
  @state quitting = false  @ 52
  @state errHandler = nil  @ 53
  @state focusFrames = 0  @ 54   -- >0: re-focus our window this many frames, counting down
  @state fxFloatOpen = false  @ 55   -- an FX float window was open at the last poll
  @state weHadFocus = false  @ 56   -- our window held focus at the end of the last frame
  @state myHwnd  @ 57   -- our OS window HWND, captured via js while we hold focus
  @state jsFocus = reaper.JS_Window_GetForeground ~= nil  @ 58   -- js_ReaScriptAPI present
  @state switcherSeg = { id = 'switcher', render = drawSwitcher }  @ 99
  @state externalCommands = {}  @ 114   -- list of { extKey, command }
  @state coord = {}  @ 289
      @contract  register instantiates page; first registered becomes active; returns page handle

# Private functions
  -- Coordinator
  @fn tick()  @ 63-71
      @contract  tick() runs once per frame before the page draws; no selection bus here
  @fn drawSwitcher()  @ 73-95
  @fn dispatch(state)  @ 101-108
  -- External commands (REAPER-keymap bridge)
  @fn pollExternalCommands()  @ 116-123
  @fn anyFxFloating()  @ 127-139
      -- Any floating FX window open across master + tracks. The poll in frame() reads
      -- its open→closed edge (X button or F11) to reclaim OS focus from REAPER.
  @fn frame()  @ 141-283

# Public API (coord:*)
  @api coord:register(name, moduleName, extra)  @ 291-296
  @api coord:setActive(name)  @ 300-313
      @contract  setActive(name) no-ops if name==active; else unbind outgoing, swap scope, bind incoming
      @contract  tracker's no-arg bind resolves its stored selection; renderBody keeps it current
  @api coord:returnToArrange()  @ 316-319
      @contract  tracker back to arrange; no reveal (cursor never left). No-op if arrange unregistered.
  @api coord:getFacade(name)  @ 322
      @contract  resolve a published page facade by name; the contents are owned by the publishing page
  @api coord:previousPage()  @ 325
      @contract  the page active immediately before the current one; closeEditor returns here
  @api coord:togglePage()  @ 329-337
      -- Cycle tracker → arrange → sample → wiring → tracker. Unregistered pages
      -- are skipped; with ≥1 track every page activates.
  @api coord:reloadAfterExternalMutation()  @ 341-346
      @contract  invoke after firing a REAPER action that mutates the bound take from inside a frame (Ctrl-Z, Ctrl-Shift-Z). The watcher's end-of-frame baseline would otherwise absorb the mutation; this reloads now so tm/vm stay coherent with the take.
      @invariant  mirror resync precedes reload — see docs/coordinator.md § Undo mid-frame
  @api coord:onExternalCommand(extKey, command)  @ 349-351
      @contract  registers an ExtState key→command bridge polled each frame to fire Continuum commands
  @api coord:quit()  @ 353
  @api coord:run(handler)  @ 355
      @contract  handler wraps every deferred frame; without it, post-frame-1 errors raise raw dialogs

